        CALL $FF98                       ; $9631  CD 98 FF
        LD ($FB37),HL                    ; $9634  22 37 FB
        LD A,$03                         ; $9637  3E 03
        LD ($FB05),A                     ; $9639  32 05 FB
        LD A,($F3B9)                     ; $963C  3A B9 F3
        SUB $03                          ; $963F  D6 03
